import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import MediaUpload from '../components/MediaUpload';
import './AddPropertyPage.css';

const API_URL = 'http://localhost:5000/api';

function AddPropertyPage() {
  const { token } = useAuth();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    area: '',
    rooms: '',
    bathrooms: '',
    floor: '',
    year: '',
    type: 'Квартира',
    city: '',
    address: ''
  });
  const [submitting, setSubmitting] = useState(false);
  const [createdPropertyId, setCreatedPropertyId] = useState(null);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    
    try {
      const response = await axios.post(`${API_URL}/properties`, formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      const newProperty = response.data;
      setCreatedPropertyId(newProperty.id);
      alert('Объявление успешно создано! Теперь вы можете добавить фотографии и видео.');
      
    } catch (error) {
      console.error('Error creating property:', error);
      alert('Ошибка при создании объявления');
    } finally {
      setSubmitting(false);
    }
  };

  const handleUploadComplete = () => {
    alert('Медиафайлы успешно загружены! Объявление отправлено на модерацию.');
    navigate('/profile');
  };

  return (
    <div className="add-property-page">
      <h1>Разместить объявление</h1>
      
      {!createdPropertyId ? (
        <form onSubmit={handleSubmit} className="property-form">
          <div className="form-group">
            <label>Название *</label>
            <input
              type="text"
              name="title"
              required
              value={formData.title}
              onChange={handleChange}
            />
          </div>

          <div className="form-group">
            <label>Описание *</label>
            <textarea
              name="description"
              rows="5"
              required
              value={formData.description}
              onChange={handleChange}
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Цена (₽) *</label>
              <input
                type="number"
                name="price"
                required
                value={formData.price}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Площадь (м²)</label>
              <input
                type="number"
                name="area"
                value={formData.area}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Комнат</label>
              <input
                type="number"
                name="rooms"
                value={formData.rooms}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Ванных комнат</label>
              <input
                type="number"
                name="bathrooms"
                value={formData.bathrooms}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Этаж</label>
              <input
                type="number"
                name="floor"
                value={formData.floor}
                onChange={handleChange}
              />
            </div>

            <div className="form-group">
              <label>Год постройки</label>
              <input
                type="number"
                name="year"
                value={formData.year}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Тип недвижимости</label>
              <select name="type" value={formData.type} onChange={handleChange}>
                <option value="Квартира">Квартира</option>
                <option value="Дом">Дом</option>
                <option value="Коммерческая">Коммерческая</option>
              </select>
            </div>

            <div className="form-group">
              <label>Город</label>
              <input
                type="text"
                name="city"
                value={formData.city}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="form-group">
            <label>Адрес</label>
            <input
              type="text"
              name="address"
              value={formData.address}
              onChange={handleChange}
            />
          </div>

          <button type="submit" className="submit-btn" disabled={submitting}>
            {submitting ? 'Создание...' : 'Создать объявление'}
          </button>
        </form>
      ) : (
        <MediaUpload propertyId={createdPropertyId} onUploadComplete={handleUploadComplete} />
      )}
    </div>
  );
}

export default AddPropertyPage;
